import {spawn, spawnSync} from 'node:child_process';
import {existsSync} from 'node:fs';
import {join} from 'node:path';
import {
	NullHarness,
	pidAlive,
	registerHarness,
	type Harness,
	type HarnessRecord,
	type LaunchInput,
	type LaunchResult,
} from './harness.js';
import type {HarnessAdapter} from './config.js';

/**
 * The **pi** harness adapter (ADR §5) — the first real agent harness
 * `agent-runner` drives. It fulfils the harness seam introduced by
 * `agent-workspaces` (`./harness.ts`): launch a job's work-agent command in its
 * worktree, and report liveness from **pi-native signals**.
 *
 * Two design commitments from the slice + ADR §5, both encoded here:
 *
 *  1. **Invocation** is the standard work-agent prompt (the constant wrapper +
 *     the slice's `## Prompt`, assembled by `./prompt.ts`) fed to the pi CLI on
 *     stdin, running non-interactively (`--print`) inside the job worktree.
 *  2. **Liveness** is reported from the **PID** (process alive?) PLUS a pointer
 *     to the pi **session dir/log** (real activity + an audit trail) — explicitly
 *     **NOT filesystem mtime**: a live agent can think for minutes without
 *     writing any files, so mtime would mistake a thinking agent for a dead one.
 *
 * pi specifics stay BEHIND this adapter; the core (`run`, `status`, `watch`)
 * talks only to the `Harness` interface. Where running real pi in CI is
 * impractical, the pi CLI is stubbed (see `pi-harness.test.ts`) via the
 * injectable `piBin`.
 *
 * ## Seam contract (what an adapter promises the core)
 *
 *  - `launch(input)` runs the work-agent command for ONE job in `input.dir`
 *    (the worktree), feeding `input.prompt` to the agent. It returns
 *    `{ok, record, detail?}`: `ok` iff the agent completed successfully, and a
 *    `record` to persist in `.agent-runner-job.json` carrying the **liveness
 *    anchor** (`pid`) plus an adapter-specific `session` pointer. The core treats
 *    the call as blocking (it runs the test gate immediately after) — like the
 *    null adapter, pi runs to completion here, so by the time `launch` returns
 *    the agent is done and `isAlive` correctly reads it as not-alive.
 *  - `isAlive(record)` answers liveness FROM THE RECORD'S ANCHOR (PID/session),
 *    never mtime, so a separate `status`/`watch` process can re-derive liveness
 *    from a fresh process WITHOUT re-launching the agent.
 */

/** The default pi CLI binary name (resolved on `PATH`). */
export const DEFAULT_PI_BIN = 'pi';

/**
 * The subdirectory (inside a job worktree) where pi stores its session files /
 * log. We point pi at this dir (`--session-dir`) so the session pointer we
 * record is deterministic and lives WITH the job (an audit trail `status`/`gc`
 * can find), rather than wherever pi's global default would land it.
 */
export const PI_SESSION_DIRNAME = '.agent-runner-pi-session';

/** Compute the pi session dir for a job worktree at `dir`. */
export function piSessionDir(dir: string): string {
	return join(dir, PI_SESSION_DIRNAME);
}

export interface PiHarnessOptions {
	/**
	 * The pi CLI binary (default `pi` on `PATH`). Tests inject a stub script here
	 * so the seam can be exercised without a real model call / network.
	 */
	piBin?: string;
	/**
	 * Extra arguments inserted before the `--print` invocation (e.g. a pinned
	 * `--model`). The adapter always supplies `--print` + `--session-dir`; these
	 * layer on top for operator control.
	 */
	extraArgs?: string[];
}

/**
 * The pi harness block persisted in a job record. It extends the base
 * {@link HarnessRecord} with pi's concrete liveness pointer — the **session
 * dir** — alongside the PID. `gc`/`status` re-derive liveness from these without
 * re-launching pi.
 */
export interface PiHarnessRecord extends HarnessRecord {
	adapter: 'pi';
	/** Absolute path to the pi session dir/log (the activity + audit pointer). */
	session?: string;
}

/**
 * The pi adapter. Invocation: `pi [--model <model>] --print --session-dir
 * <job>/<session> [extra]` run in the worktree with the work-agent prompt on
 * stdin. The model is passed NATIVELY as `--model <model>` when set (ADR §13 —
 * the routing intent agent-runner controls); auth/keys stay pi's job, never
 * agent-runner's. Liveness: the PID is
 * the authoritative "is it running?" signal; the recorded `session` dir/log is
 * the activity + audit pointer surfaced alongside it. NEVER mtime (ADR §5).
 */
export class PiHarness implements Harness {
	readonly adapter = 'pi';
	private readonly piBin: string;
	private readonly extraArgs: string[];

	constructor(options: PiHarnessOptions = {}) {
		this.piBin = options.piBin ?? DEFAULT_PI_BIN;
		this.extraArgs = options.extraArgs ?? [];
	}

	launch(input: LaunchInput): LaunchResult {
		const sessionDir = piSessionDir(input.dir);
		// The model ROUTING intent (ADR §13): when set, pass it NATIVELY as
		// `--model <model>`. agent-runner only chooses the model; pi owns auth/keys.
		const modelArgs =
			input.model !== undefined && input.model !== ''
				? ['--model', input.model]
				: [];
		// Non-interactive (`--print`): pi processes the prompt and exits. We pin the
		// session dir INTO the job worktree so the recorded pointer is deterministic
		// and travels with the job (an audit trail), not pi's global default. The
		// operator's `extraArgs` still layer on (e.g. flags beyond `--model`).
		const args = [
			...modelArgs,
			...this.extraArgs,
			'--print',
			'--session-dir',
			sessionDir,
		];
		const result = spawnSync(this.piBin, args, {
			cwd: input.dir,
			encoding: 'utf8',
			input: input.prompt,
			env: input.env ?? process.env,
			maxBuffer: 64 * 1024 * 1024,
		});
		if (result.error) {
			throw new Error(
				`failed to spawn pi (${this.piBin}): ${result.error.message}`,
			);
		}
		// Record the pi child's PID (the liveness anchor) + the session dir/log
		// pointer (the pi-native activity + audit trail). Liveness later reads these
		// — NOT a filesystem mtime (ADR §5).
		const record: PiHarnessRecord = {
			adapter: 'pi',
			pid: result.pid,
			command: [this.piBin, ...args].join(' '),
			session: sessionDir,
		};
		const status = result.status ?? -1;
		return {
			ok: status === 0,
			record,
			detail: status === 0 ? undefined : (result.stderr ?? '').trim(),
		};
	}

	/**
	 * Liveness from pi-native signals (ADR §5): the PID (`process.kill(pid, 0)`,
	 * the OS process table) answers "is the agent process running?" — the
	 * authoritative signal. NEVER filesystem mtime. The recorded session dir/log
	 * is the audit/activity pointer surfaced alongside (see {@link sessionPointer}).
	 */
	/**
	 * The ASYNC twin of {@link launch} — IDENTICAL semantics (same `--print
	 * --session-dir` invocation, same prompt on stdin, output still CAPTURED, same
	 * `LaunchResult` shape: PID anchor + session pointer + ok/detail), but launched
	 * NON-BLOCKING with `spawn` instead of the synchronous `spawnSync`. This is the
	 * one structural carve-out the `do --watch` observer needs (slice `do-watch`):
	 * `spawnSync` blocks the event loop until pi exits, so NOTHING could tail the
	 * growing session `.jsonl` concurrently. `launchAsync` runs pi alongside the
	 * tailer; the WHOLE launch delta is `spawnSync` → `spawn`. It is NOT a switch
	 * to inherited-stdio piping (that is the separate future `--agent` seam) — the
	 * prompt is still fed on stdin and stdout/stderr are still captured; we read
	 * the `.jsonl` LOG, never piped stdout. With or without `--watch` the run's
	 * outcome/gate/git/exit are identical.
	 */
	launchAsync(input: LaunchInput): Promise<LaunchResult> {
		const sessionDir = piSessionDir(input.dir);
		const modelArgs =
			input.model !== undefined && input.model !== ''
				? ['--model', input.model]
				: [];
		const args = [
			...modelArgs,
			...this.extraArgs,
			'--print',
			'--session-dir',
			sessionDir,
		];
		const record: PiHarnessRecord = {
			adapter: 'pi',
			command: [this.piBin, ...args].join(' '),
			session: sessionDir,
		};
		return new Promise<LaunchResult>((resolve, reject) => {
			const child = spawn(this.piBin, args, {
				cwd: input.dir,
				env: input.env ?? process.env,
				stdio: ['pipe', 'pipe', 'pipe'],
			});
			record.pid = child.pid; // the liveness anchor, recorded like spawnSync.
			let stderr = '';
			child.stderr?.on('data', (chunk: Buffer) => {
				stderr += chunk.toString('utf8');
			});
			// Output is CAPTURED (not piped through) — `--watch` reads the .jsonl log,
			// not stdout. We drain stdout so the pipe never fills and stalls pi.
			child.stdout?.on('data', () => {});
			child.on('error', (err) => {
				reject(new Error(`failed to spawn pi (${this.piBin}): ${err.message}`));
			});
			child.on('close', (code) => {
				const status = code ?? -1;
				resolve({
					ok: status === 0,
					record,
					detail: status === 0 ? undefined : stderr.trim(),
				});
			});
			// Feed the same prepared prompt on stdin, then close it (pi reads to EOF).
			if (input.prompt !== undefined) {
				child.stdin?.write(input.prompt);
			}
			child.stdin?.end();
		});
	}

	isAlive(record: HarnessRecord): boolean {
		return pidAlive(record.pid);
	}

	/**
	 * The recorded pi session dir/log pointer for a job — the pi-native activity +
	 * audit trail surfaced alongside PID liveness. `undefined` when the record has
	 * no session pointer (e.g. a non-pi or legacy record). Existence on disk is
	 * reported separately so callers can distinguish "recorded but gone" from
	 * "never recorded".
	 */
	sessionPointer(record: HarnessRecord): string | undefined {
		return record.session;
	}
}

/**
 * Does a job record carry a live pi session dir/log on disk? Combines the
 * recorded pointer with an `existsSync` check. This is the pi-native "is there
 * an audit trail to look at?" signal — distinct from PID liveness, and STILL not
 * mtime (we check existence, never modification time).
 */
export function piSessionExists(record: HarnessRecord): boolean {
	return record.session !== undefined && existsSync(record.session);
}

// Register the pi adapter so `status`/`watch`/`gc` resolve liveness for `pi`
// jobs to THIS adapter (PID + session pointer) rather than the null fallback.
// A default-configured instance is sufficient for liveness (the binary/extra
// args only matter for `launch`, which the core does via an explicit instance).
registerHarness(new PiHarness());

/**
 * Build the harness that LAUNCHES jobs for a run, from config (ADR §5): `pi`
 * ⇒ the pi adapter (invoking `config.piBin`); anything else ⇒ the null adapter
 * (shelling out to `agentCmd`). This is the single place the core turns the
 * declared `harness` selector into a concrete adapter, keeping pi specifics
 * behind the seam.
 */
export function createHarness(options: {
	harness?: HarnessAdapter;
	piBin?: string;
}): Harness {
	if (options.harness === 'pi') {
		return new PiHarness({piBin: options.piBin});
	}
	return new NullHarness();
}

import {existsSync, readdirSync, statSync} from 'node:fs';
import {open, type FileHandle} from 'node:fs/promises';
import {join} from 'node:path';

/**
 * The **`do --watch` observer** (slices `do-watch` + `do-watch-session-log-format`)
 * — a READ-ONLY concurrent tail of the pi session `.jsonl` event log, restoring
 * for `do` the live agent-conversation view `ar-run.sh --watch` gave.
 *
 * `ar-run.sh --watch` piped `pi -p --mode json | jq` to surface the high-signal
 * events; `do` runs the agent CAPTURED through the harness seam, so that live
 * view was lost. The pi adapter already writes a session `.jsonl` to its
 * `--session-dir` (`piSessionDir(dir)`) — but that is pi's SESSION-PERSISTENCE
 * log, a DIFFERENT format from the `--mode json` STREAM `ar-run.sh` piped.
 *
 * A session-log record is `{"type":"message", "message":{role, content[]}}` (or a
 * `session`/`model_change`/`thinking_level_change` preamble record). The earlier
 * classifier matched the STREAM vocabulary (`tool_start`/`message_end`/`agent_end`),
 * none of which occur in the session log — so every line fell through to skip and
 * `do --watch` was silently a no-op. This module tails the growing session log and
 * surfaces the same high-signal level `ar-run.sh --watch` gave, read off the
 * SESSION-LOG shape:
 *
 *   - an `assistant` `message` → its `content[]` `text` parts, then `▶ <name>`
 *     (cyan) per `content[]` `toolCall` part;
 *   - `✓ agent finished` (green) on PROCESS EXIT — the session log has no
 *     `agent_end` event, so the tailer emits it once on `stop()`;
 *   - everything else (`session`/`model_change`/user messages/tool results/…) →
 *     skipped.
 *
 * The classifier mirrors pi-remote's `session-pool.ts` reference parser (`type` →
 * `role` → `content[]` block walk over `thinking`/`text`/`toolCall`, incl.
 * `tc.name||tc.toolName` and content-as-string). The JSONL is parsed in TS (NO
 * `jq` — that bash dependency is part of what `do` replaces). It is a PURE
 * OBSERVER: it only READS the log; it never changes the run's outcome, gate,
 * integration, git, or exit code. Colour is honoured ONLY on a TTY / when
 * `NO_COLOR` is unset (the same rule as `output.ts`), threaded in by the caller
 * as a boolean.
 */

// The same conventional ANSI codes `ar-run.sh`'s jq filter emitted (cyan tool
// marker, green finished marker, reset). Colour is applied ONLY when the caller
// passes `color: true` (its TTY/NO_COLOR decision); plain otherwise.
const CYAN = '\u001b[36m';
const GREEN = '\u001b[32m';
const RESET = '\u001b[0m';

/** Wrap `text` in `code` + reset when `color`, else return it unchanged. */
function paint(text: string, color: boolean, code: string): string {
	return color ? `${code}${text}${RESET}` : text;
}

/**
 * A structural view of the pi SESSION-LOG records we classify. It mirrors the
 * `@earendil-works/pi-coding-agent` `SessionEntry` / `SessionMessageEntry`
 * shapes (`type:"message"` with a nested `message.role` + `message.content`) but
 * is declared locally so the observer needs no runtime dependency on that
 * package's (heavy) type tree — agent-runner does not otherwise depend on it.
 * The content blocks are read defensively (like pi-remote's reference parser,
 * which casts them via `as any`): a content part may be a `text`, a `thinking`,
 * or a `toolCall` (whose name is `name` OR `toolName`), or the whole content may
 * be a plain string.
 */
interface SessionLogRecord {
	type?: unknown;
	message?: {
		role?: unknown;
		content?: unknown;
	};
}

/** The green `✓ agent finished` line, emitted on PROCESS EXIT (not a log event). */
export function finishedLine(color: boolean): string {
	return paint('✓ agent finished', color, GREEN);
}

/**
 * Parse ONE pi SESSION-LOG `.jsonl` line and return the high-signal lines to
 * surface — or `[]` to SKIP it. This is the pure, unit-testable classifier,
 * mirroring pi-remote's `session-pool.ts` block walk:
 *
 *   - a `{type:"message", message:{role:"assistant", content}}` record → for each
 *     `content[]` part: a `text` part yields its text (parts concatenated into
 *     ONE line, like the old `jq` `.content[]` select); a `toolCall` part yields
 *     `▶ <name>` (cyan; `name` OR `toolName`, defaulting to `tool`); a `thinking`
 *     part (and anything else) is skipped. A plain-string `content` yields one
 *     text line.
 *   - everything else (`session`/`model_change`/`thinking_level_change`, user
 *     messages, tool results, blank/malformed lines) → `[]` (skipped).
 *
 * "Finished" is NOT a record here — the session log has no `agent_end`; the
 * tailer emits {@link finishedLine} on process exit instead.
 *
 * Malformed JSON is skipped (not thrown): a partially-written trailing line in a
 * growing log must not crash the observer.
 */
export function formatWatchEvent(line: string, color: boolean): string[] {
	const trimmed = line.trim();
	if (trimmed === '') {
		return [];
	}
	let event: unknown;
	try {
		event = JSON.parse(trimmed);
	} catch {
		// A half-written trailing line in a growing log — skip, never throw.
		return [];
	}
	if (typeof event !== 'object' || event === null) {
		return [];
	}
	const record = event as SessionLogRecord;
	if (record.type !== 'message') {
		return [];
	}
	const message = record.message;
	if (!message || message.role !== 'assistant') {
		// Skip user turns, tool results, and any non-assistant message.
		return [];
	}
	return assistantLines(message.content, color);
}

/**
 * Walk an assistant `message.content` into the lines to surface, mirroring
 * pi-remote's `session-pool.ts` reference parser. The `text` parts are
 * concatenated into a SINGLE leading line (so a multi-part assistant turn reads
 * as one sentence, as `ar-run.sh --watch` showed it); each `toolCall` part adds a
 * `▶ <name>` line after it. A plain-string content yields the single text line.
 * `thinking` parts and any other block type are skipped.
 */
function assistantLines(content: unknown, color: boolean): string[] {
	if (typeof content === 'string') {
		return content === '' ? [] : [content];
	}
	if (!Array.isArray(content)) {
		return [];
	}
	const lines: string[] = [];
	const textParts: string[] = [];
	for (const part of content) {
		if (typeof part !== 'object' || part === null) {
			continue;
		}
		const p = part as Record<string, unknown>;
		if (p.type === 'text' && typeof p.text === 'string') {
			textParts.push(p.text);
		} else if (p.type === 'toolCall') {
			const name =
				(typeof p.name === 'string' && p.name !== '' && p.name) ||
				(typeof p.toolName === 'string' && p.toolName !== '' && p.toolName) ||
				'tool';
			lines.push(paint(`▶ ${name}`, color, CYAN));
		}
		// `thinking` and any other block type are skipped.
	}
	const text = textParts.join('');
	return text === '' ? lines : [text, ...lines];
}

/** The session `.jsonl` file extension pi writes its event log under. */
const SESSION_LOG_EXT = '.jsonl';

/**
 * Find the session `.jsonl` event log inside a pi `--session-dir`, or
 * `undefined` if none exists yet. pi writes a single session file there; when
 * more than one is present (a reused dir) the most-recently-modified is chosen,
 * so a fresh run's log is tailed rather than a stale one.
 */
export function findSessionLog(sessionDir: string): string | undefined {
	if (!existsSync(sessionDir)) {
		return undefined;
	}
	let newest: {path: string; mtimeMs: number} | undefined;
	for (const name of readdirSync(sessionDir)) {
		if (!name.endsWith(SESSION_LOG_EXT)) {
			continue;
		}
		const path = join(sessionDir, name);
		let mtimeMs: number;
		try {
			mtimeMs = statSync(path).mtimeMs;
		} catch {
			continue;
		}
		if (newest === undefined || mtimeMs >= newest.mtimeMs) {
			newest = {path, mtimeMs};
		}
	}
	return newest?.path;
}

export interface SessionTailerOptions {
	/** The pi session dir to tail the `.jsonl` event log from. */
	sessionDir: string;
	/** Emit ANSI colour (the caller's TTY/`NO_COLOR` decision). */
	color: boolean;
	/** Where formatted high-signal lines are written (defaults to stderr). */
	sink?: (line: string) => void;
	/** How often (ms) to poll for new bytes / the log's appearance. */
	pollIntervalMs?: number;
}

const DEFAULT_POLL_INTERVAL_MS = 100;

/**
 * A concurrent, READ-ONLY tail of the pi session `.jsonl`. It polls the session
 * dir for the log (which the pi adapter creates only once pi starts), then reads
 * newly-appended bytes, splits them into complete lines, and surfaces each via
 * {@link formatWatchEvent}. A partial trailing line is buffered until its
 * newline arrives, so an event split across two reads is never mis-parsed.
 *
 * It is a pure observer: nothing it does feeds back into the run. `start()`
 * begins polling; `stop()` performs one final drain (to catch events written
 * just before the agent exited), emits the `✓ agent finished` line ONCE (the
 * session log has no `agent_end` — process exit IS the finish signal), and
 * releases the file handle. Created and driven by `do --watch` ALONGSIDE the
 * (async) agent launch; `stop()` runs when that launch returns (i.e. the agent
 * process exited).
 */
export class SessionTailer {
	private readonly sessionDir: string;
	private readonly color: boolean;
	private readonly sink: (line: string) => void;
	private readonly pollIntervalMs: number;

	private handle: FileHandle | undefined;
	private offset = 0;
	private pending = '';
	private timer: NodeJS.Timeout | undefined;
	private polling = false;
	private stopped = false;
	private finishedEmitted = false;

	constructor(options: SessionTailerOptions) {
		this.sessionDir = options.sessionDir;
		this.color = options.color;
		this.sink = options.sink ?? ((line) => process.stderr.write(`${line}\n`));
		this.pollIntervalMs = options.pollIntervalMs ?? DEFAULT_POLL_INTERVAL_MS;
	}

	/** Begin polling the session dir for the log and tailing its new bytes. */
	start(): void {
		if (this.timer !== undefined || this.stopped) {
			return;
		}
		this.timer = setInterval(() => {
			void this.poll();
		}, this.pollIntervalMs);
		// `unref` so an orphaned timer never keeps the process alive past the run.
		this.timer.unref?.();
	}

	/**
	 * Stop tailing: one final drain (events written right before the agent exited
	 * must still be surfaced), emit the `✓ agent finished` line ONCE (process exit
	 * is the finish signal — the session log carries no `agent_end`), then release
	 * the handle. Idempotent: a second `stop()` re-emits nothing.
	 */
	async stop(): Promise<void> {
		const wasStopped = this.stopped;
		this.stopped = true;
		if (this.timer !== undefined) {
			clearInterval(this.timer);
			this.timer = undefined;
		}
		if (!wasStopped) {
			await this.drain();
		}
		if (this.handle !== undefined) {
			await this.handle.close();
			this.handle = undefined;
		}
		if (!this.finishedEmitted) {
			this.finishedEmitted = true;
			this.sink(finishedLine(this.color));
		}
	}

	/** One poll tick: ensure the handle is open, then drain new bytes. */
	private async poll(): Promise<void> {
		if (this.polling) {
			return; // a slow read must not overlap the next tick.
		}
		this.polling = true;
		try {
			await this.drain();
		} catch {
			// A transient read error (the log being rotated/created) — try next tick.
		} finally {
			this.polling = false;
		}
	}

	/** Open the log if not yet open, read appended bytes, surface whole lines. */
	private async drain(): Promise<void> {
		if (this.handle === undefined) {
			const logPath = findSessionLog(this.sessionDir);
			if (logPath === undefined) {
				return; // log not written yet — wait for it.
			}
			this.handle = await open(logPath, 'r');
		}
		const stats = await this.handle.stat();
		if (stats.size <= this.offset) {
			return; // no new bytes.
		}
		const length = stats.size - this.offset;
		const buffer = Buffer.alloc(length);
		const {bytesRead} = await this.handle.read(buffer, 0, length, this.offset);
		this.offset += bytesRead;
		this.pending += buffer.toString('utf8', 0, bytesRead);
		this.flushLines();
	}

	/** Split the buffer on newlines, surfacing each COMPLETE line; keep the rest. */
	private flushLines(): void {
		let newlineIndex = this.pending.indexOf('\n');
		while (newlineIndex !== -1) {
			const line = this.pending.slice(0, newlineIndex);
			this.pending = this.pending.slice(newlineIndex + 1);
			// A single record may surface MULTIPLE lines (assistant text + each of
			// its tool starts), or none (skipped record types).
			for (const formatted of formatWatchEvent(line, this.color)) {
				this.sink(formatted);
			}
			newlineIndex = this.pending.indexOf('\n');
		}
	}
}

import {spawnSync} from 'node:child_process';

/**
 * The **harness seam** (ADR §5): how a job's command is launched and how its
 * liveness is observed is pluggable behind an adapter; the core never hard-codes
 * a specific tool.
 *
 * Crucially, **liveness is reported by the harness, NOT inferred from filesystem
 * mtime**: a live agent can think for minutes without writing any files, so
 * mtime would mistake a thinking agent for a dead one. Adapters answer liveness
 * from the real signal (the PID, a session handle, …) — never mtime.
 *
 * This slice ships the **null adapter** (records a PID, runs a configured
 * command) so the substrate is testable standalone. The first real target (the
 * `pi` adapter: liveness via PID + a pointer to the pi session dir/log,
 * invocation via the pi CLI) is its own slice.
 */

/**
 * The persisted harness block in a job's `.agent-runner-job.json` record. It
 * captures which adapter launched the job + the liveness pointer the adapter
 * needs to answer `isAlive` later (so `gc`/`status` can re-derive liveness from
 * a fresh process without re-launching). Adapter-specific fields are optional.
 */
export interface HarnessRecord {
	/** Which harness adapter owns this job (`null`, later `pi`, …). */
	adapter: string;
	/** OS process id of the launched command (the liveness anchor). */
	pid?: number;
	/** The command the adapter ran (for audit / re-launch). */
	command?: string;
	/** Adapter-specific session pointer (e.g. the pi session dir/log path). */
	session?: string;
}

/** What a harness needs to launch one job's command. */
export interface LaunchInput {
	/** The job's working directory (the worktree) — the command runs here. */
	dir: string;
	/** The slug being processed (for adapters that name/log per slug). */
	slug: string;
	/** The command to run (e.g. the configured `agentCmd`). */
	command: string;
	/** Optional prompt fed on the command's stdin. */
	prompt?: string;
	/**
	 * The model the agent should run on (the harness-agnostic routing intent, ADR
	 * §13). `undefined` ⇒ agent-runner forces no model. The ADAPTER decides HOW
	 * this reaches its tool: the pi adapter passes `--model <model>` natively; the
	 * null/shell adapter substitutes a `{model}` placeholder in `command` (see
	 * {@link substituteModel}). auth/keys are NEVER carried here — they stay the
	 * harness's job.
	 */
	model?: string;
	env?: NodeJS.ProcessEnv;
}

/** The `{model}` placeholder the null/shell adapter substitutes in `agentCmd`. */
export const MODEL_PLACEHOLDER = '{model}';

/**
 * Inject the model ROUTING intent (ADR §13) into a shell `command` for the
 * null/shell adapter, with three degradation rules so model routing is OFFERED,
 * never FORCED:
 *
 *  1. `{model}` present + `model` set ⇒ substitute every occurrence.
 *  2. `{model}` present + `model` unset ⇒ a clear config error (we never emit a
 *     literal `{model}` to the shell — that would silently misroute).
 *  3. `{model}` absent ⇒ return `command` as-is (a user who bakes the model into
 *     `agentCmd`, or relies on the harness's own default, is untouched).
 *
 * agent-runner only moves the model INTENT; auth/keys stay the harness's job.
 */
export function substituteModel(
	command: string,
	model: string | undefined,
): string {
	if (!command.includes(MODEL_PLACEHOLDER)) {
		return command; // rule 3: no placeholder ⇒ run as-is.
	}
	if (model === undefined || model === '') {
		throw new Error(
			`agentCmd contains a ${MODEL_PLACEHOLDER} placeholder but no model is ` +
				`configured. Set a model (--model, AGENT_RUNNER_MODEL, per-repo, or ` +
				`global config) or remove ${MODEL_PLACEHOLDER} from agentCmd.`,
		);
	}
	return command.split(MODEL_PLACEHOLDER).join(model); // rule 1: substitute.
}

export interface LaunchResult {
	/** True iff the launched command completed successfully. */
	ok: boolean;
	/** The harness block to persist in the job record (PID, command, …). */
	record: HarnessRecord;
	/** Failure detail when `ok` is false. */
	detail?: string;
}

/**
 * The harness seam. `launch` starts the job's command + returns the record (with
 * the liveness anchor); `isAlive` answers liveness FROM THE HARNESS (PID/session
 * — never mtime, ADR §5).
 */
export interface Harness {
	/** A stable adapter name (`null`, `pi`, …) stamped into the record. */
	readonly adapter: string;
	/** Launch the job's command; record the PID + liveness pointer. */
	launch(input: LaunchInput): LaunchResult;
	/** Is the job still alive? Answered from the record's anchor, NOT mtime. */
	isAlive(record: HarnessRecord): boolean;
}

/**
 * The **null adapter**: runs the configured command synchronously to completion
 * in the job dir, recording the PID. Liveness is `process.kill(pid, 0)` against
 * the recorded PID (the OS process table) — explicitly NOT a file mtime. Because
 * it runs synchronously, the process has already exited by the time `launch`
 * returns, so a finished job reads as not-alive (which is correct).
 */
export class NullHarness implements Harness {
	readonly adapter = 'null';

	launch(input: LaunchInput): LaunchResult {
		// Inject the model routing intent into the shell command via the `{model}`
		// placeholder (ADR §13) — offered, never forced (see substituteModel).
		const command = substituteModel(input.command, input.model);
		const result = spawnSync('bash', ['-c', command], {
			cwd: input.dir,
			encoding: 'utf8',
			input: input.prompt,
			env: input.env ?? process.env,
			maxBuffer: 64 * 1024 * 1024,
		});
		if (result.error) {
			throw new Error(
				`failed to spawn harness command: ${result.error.message}`,
			);
		}
		// Record the CHILD's PID (the liveness anchor) — not the runner's. The null
		// adapter runs synchronously, so by the time we return the child has
		// exited, and `isAlive` correctly reads it as not-alive (from the PID
		// table, NOT a file mtime).
		const record: HarnessRecord = {
			adapter: this.adapter,
			pid: result.pid,
			command,
		};
		const status = result.status ?? -1;
		return {
			ok: status === 0,
			record,
			detail: status === 0 ? undefined : (result.stderr ?? '').trim(),
		};
	}

	isAlive(record: HarnessRecord): boolean {
		return pidAlive(record.pid);
	}
}

/**
 * Resolve the harness adapter that OWNS a given job record, keyed off the
 * record's `adapter` field. The core (`status`, `watch`, `gc`) reads liveness
 * for a heterogeneous set of jobs (some null, some pi) from their persisted
 * records, so it must ask the RIGHT adapter per job — a pi job's liveness is the
 * pi adapter's responsibility (PID + session pointer), not the null adapter's.
 *
 * Adapters register here lazily via {@link registerHarness}; an unknown adapter
 * falls back to the null adapter (PID-only liveness — never mtime), which is a
 * safe superset for any PID-anchored record.
 */
export function resolveHarness(record: HarnessRecord): Harness {
	return HARNESS_REGISTRY.get(record.adapter) ?? FALLBACK_HARNESS;
}

/**
 * Register a harness adapter under its `adapter` name so {@link resolveHarness}
 * can dispatch liveness to it. Idempotent (last registration wins). The pi
 * adapter registers itself on import; tests may register stubs.
 */
export function registerHarness(harness: Harness): void {
	HARNESS_REGISTRY.set(harness.adapter, harness);
}

const FALLBACK_HARNESS = new NullHarness();
const HARNESS_REGISTRY = new Map<string, Harness>([
	[FALLBACK_HARNESS.adapter, FALLBACK_HARNESS],
]);

/**
 * Is `pid` a live process? Uses signal 0 (`process.kill(pid, 0)`), which checks
 * for existence/permission WITHOUT delivering a signal — the OS process table,
 * never a filesystem mtime. Unknown/undefined PID ⇒ not alive.
 */
export function pidAlive(pid: number | undefined): boolean {
	if (pid === undefined || pid <= 0) {
		return false;
	}
	try {
		process.kill(pid, 0);
		return true;
	} catch (err) {
		// EPERM means the process exists but we may not signal it ⇒ still alive.
		return (err as NodeJS.ErrnoException).code === 'EPERM';
	}
}

import {readFileSync, writeFileSync, existsSync, mkdirSync} from 'node:fs';
import {homedir} from 'node:os';
import {dirname, join} from 'node:path';

/**
 * How a completed item is integrated back to the arbiter's `main`. `merge` lands
 * it directly on `main` (ff/rebase + push); `propose` pushes a branch + requests
 * review. (`propose` is provider-neutral; the old `pr` name was GitHub jargon.
 * See ADR §6.)
 */
export type IntegrationMode = 'propose' | 'merge';

/**
 * Which harness adapter (ADR §5) launches a job's agent and reports its
 * liveness: `null` (shell out to `agentCmd`) or `pi` (the pi CLI). Selected via
 * the `harness` config field; defaults to `null`.
 */
export type HarnessAdapter = 'null' | 'pi';

/**
 * The `propose`-mode review-request provider (ADR §6): `github` (`gh pr
 * create`) or `none` (push-only + manual instructions). Normally LEFT UNSET so
 * it auto-detects from the arbiter URL (a GitHub remote ⇒ `github`, else
 * `none`); set it to force a provider (override detection). `merge` mode is
 * provider-agnostic and ignores this.
 */
export type ReviewProviderName = 'none' | 'github';

/**
 * The per-repo acceptance gate: a single shell command, or an ordered list of
 * commands run in sequence (all must pass). See `verify.ts` / ADR §8.
 */
export type VerifyConfig = string | string[];

/**
 * Resolved runner configuration. There is NO `roots`/`remotes` field: discovery
 * is the registered hub-mirror set under `<workspacesDir>/repos/` (the registry,
 * ADR `command-surface-and-journeys` §1), NOT a config roots walk. `scan` reads
 * the eligibility fields per repo; `run --once` additionally consumes the
 * execution fields (maxParallel, perRepoMax, defaultArbiter, integration,
 * agentCmd).
 */
export interface Config {
	/**
	 * Per-repo policy: may agents claim *undeclared* (not `humanOnly`) slices in
	 * this repo? `false` (default, strict) ⇒ agents claim nothing automatically;
	 * `true` ⇒ agents may claim any slice that is not `humanOnly: true`. Resolved
	 * like `integration`: flag (`--allow-agents`/`--no-allow-agents`) > per-repo >
	 * global > default.
	 */
	allowAgents: boolean;
	/** Global cap on how many items the runner claims+runs in one tick. */
	maxParallel: number;
	/** Per-repo cap on concurrent claims (≤ maxParallel in effect). */
	perRepoMax: number;
	/** Name of the git remote that serializes claims (the arbiter). */
	defaultArbiter: string;
	/**
	 * The execution working area: bare hub mirrors (`<dir>/repos/<key>.git`) and
	 * job worktrees (`<dir>/work/<work-id>/`). STATE, not cache (ADR §3) — lives
	 * under a single visible `~/.agent-runner/`, NEVER `~/.cache`. Overridable so
	 * tests (and unusual setups) can relocate it.
	 */
	workspacesDir: string;
	/**
	 * Where local `--bare` arbiters (offline source of truth) are provisioned:
	 * `<dir>/<host>/<org>/<name>.git` (hierarchical, reusing the repo→key
	 * encoding). Arbiters are precious DATA, not state/cache (ADR §7): they live
	 * under a visible `~/git/` and MUST NEVER be placed under `~/.agent-runner/`
	 * (a `gc`/cleanup mishap could nuke the only copy). Overridable so tests can
	 * relocate it.
	 */
	arbitersDir: string;
	/**
	 * Where the HUMAN `work-on` command checks out its parallel worktrees:
	 * `<dir>/<key>/<slug>/` on branch `work/<slug>`. This is a **human-only**,
	 * editor-facing area — deliberately NOT under `~/.agent-runner/` (the agents'
	 * execution state, ADR §3), so a `work-on` worktree never carries the human's
	 * secrets into an agent context. It is intentionally OPTIONAL with **no silent
	 * default**: `work-on` prompts for it on first use and saves it here (offering a
	 * sensible suggestion that does NOT share a prefix with the user's code dirs, so
	 * shell tab-completion never collides). `undefined` ⇒ not yet configured.
	 */
	humanWorktreesDir?: string;
	/** Integration mode for completed items: `propose` (default) or `merge`. */
	integration: IntegrationMode;
	/**
	 * The `propose`-mode review-request provider (ADR §6). Optional with NO
	 * default so "unset" is distinguishable from an explicit value: unset ⇒
	 * auto-detect from the arbiter URL (GitHub remote ⇒ `github`, else `none`);
	 * an explicit `github`/`none` OVERRIDES detection. `merge` mode ignores it
	 * (provider-agnostic git). The core never imports `gh`; only the GitHub
	 * adapter shells out to it.
	 */
	provider?: ReviewProviderName;
	/**
	 * The command the runner shells out to for one slice. The runner appends the
	 * built prompt on stdin; the command does NO git ops on the repo (the runner
	 * owns those). Empty string ⇒ no agent configured (run will refuse). Consumed
	 * by the **null** harness adapter (it shells out to this verbatim); the **pi**
	 * adapter ignores it (it invokes the pi CLI directly — see `harness`).
	 */
	agentCmd: string;
	/**
	 * The model a job's agent runs on (harness-agnostic ROUTING intent, ADR §13).
	 * agent-runner decides WHICH model; it never touches auth/keys (those stay the
	 * harness's job). Optional with NO default so "unset" is meaningful: unset ⇒
	 * agent-runner forces no model (the harness's own default / a model baked into
	 * `agentCmd` is used untouched). Carried through the harness seam
	 * (`LaunchInput.model`); the ADAPTER decides HOW it reaches its tool — the pi
	 * adapter passes `--model <model>` natively, the null/shell adapter substitutes
	 * a `{model}` placeholder in `agentCmd`. Resolved per-repo like `integration`:
	 * flag (`--model`) > env > per-repo > global > default (unset).
	 */
	model?: string;
	/**
	 * Which harness adapter launches + reports liveness for a job's agent (the
	 * harness seam, ADR §5): `null` (default — shells out to `agentCmd`,
	 * PID-only liveness) or `pi` (invokes the pi CLI with the work-agent prompt;
	 * liveness from PID + the pi session dir/log, never mtime). pi specifics stay
	 * behind the adapter; the core only sees the `Harness` interface.
	 */
	harness?: HarnessAdapter;
	/**
	 * The pi CLI binary the `pi` harness invokes (default `pi` on `PATH`).
	 * Overridable so an operator can pin a path; tests stub it. Ignored unless
	 * `harness` is `pi`.
	 */
	piBin?: string;
	/**
	 * The per-repo acceptance gate run by `agent-runner verify` (a deterministic
	 * shell command, or an ordered list of commands). NOT per-slice and NOT model-
	 * interpreted — it is declared, auditable config (ADR §8). Unset (omitted) ⇒
	 * a sensible `pnpm -r build && test && format:check` default; the field is
	 * intentionally optional so "unset" is distinguishable from "empty".
	 */
	verify?: VerifyConfig;
}

/** A partial config, e.g. loaded from a JSON file or built from CLI flags. */
export type PartialConfig = Partial<Config>;

/**
 * Built-in defaults. Chosen so that zero-config is useful: stay strict about the
 * autonomy gate (agents claim nothing unless a repo opts in via `allowAgents`).
 * Discovery has no default `roots` — it is the registered hub-mirror set (empty
 * until `remote add`/`remote find` registers a target).
 */
export const DEFAULT_CONFIG: Config = {
	allowAgents: false,
	maxParallel: 4,
	perRepoMax: 2,
	defaultArbiter: 'origin',
	workspacesDir: join(homedir(), '.agent-runner'),
	arbitersDir: join(homedir(), 'git'),
	integration: 'propose',
	agentCmd: '',
};

/** The conventional config location (`~/.config/agent-runner/config.json`). */
export function defaultConfigPath(): string {
	return join(homedir(), '.config', 'agent-runner', 'config.json');
}

/** Merge a partial config over the built-in defaults; arrays are replaced. */
export function mergeConfig(overrides: PartialConfig): Config {
	const merged: Config = {...DEFAULT_CONFIG};
	// Iterate the override's own keys (not the defaults') so optional keys like
	// `verify` (absent from DEFAULT_CONFIG, left unset by design) are carried over.
	for (const key of Object.keys(overrides) as (keyof Config)[]) {
		const value = overrides[key];
		if (value !== undefined) {
			// Assign through `unknown`: each key's value type matches by construction.
			(merged as Record<keyof Config, unknown>)[key] = value;
		}
	}
	return merged;
}

/**
 * Persist `config` to `path` as pretty JSON (creating the parent dir). Used by
 * `work-on` to SAVE the prompted `humanWorktreesDir` on first use so the human is
 * never asked again. Only the keys present in `config` are written — we round-trip
 * whatever the loader produced (defaults + file + the new key), which keeps the
 * on-disk file explicit and stable.
 */
export function saveConfig(config: PartialConfig, path: string): void {
	mkdirSync(dirname(path), {recursive: true});
	writeFileSync(path, JSON.stringify(config, null, 2) + '\n');
}

/**
 * Load config from `path`, merged over defaults. A missing file is not an error
 * (defaults make the tool work out of the box); invalid JSON is.
 */
export function loadConfig(path: string = defaultConfigPath()): Config {
	if (!existsSync(path)) {
		return mergeConfig({});
	}
	let raw: string;
	try {
		raw = readFileSync(path, 'utf8');
	} catch (err) {
		throw new Error(
			`Failed to read config at ${path}: ${(err as Error).message}`,
		);
	}
	let parsed: PartialConfig;
	try {
		parsed = JSON.parse(raw) as PartialConfig;
	} catch (err) {
		throw new Error(
			`Invalid JSON in config at ${path}: ${(err as Error).message}`,
		);
	}
	return mergeConfig(parsed);
}

import type {Config, PartialConfig} from './config.js';

/**
 * The environment-variable config layer.
 *
 * A per-machine context (a CI job, a developer's shell) can set ANY {@link Config}
 * key via an `AGENT_RUNNER_*` environment variable WITHOUT committing a file —
 * including the host-only keys (`piBin`, `agentCmd`, …) that the per-repo
 * `.agent-runner.json` deliberately rejects.
 *
 * Env is a legitimate *per-machine source* — exactly like a CLI flag or the
 * global `~/.config/agent-runner/config.json` — so it is NOT subject to the
 * per-repo allow/reject split (that split only governs the *committed repo
 * file*). This is the sharpened host-only principle (ADR §13): host-only keys
 * must come from a per-machine source (flag, env, or global file), never the
 * committed repo file; env is simply the per-machine source CI actually has
 * without writing a file.
 *
 * Resolution chain (highest wins):
 *
 *   flag > ENV (AGENT_RUNNER_*) > per-repo > global > built-in default
 *
 * Naming: `AGENT_RUNNER_<SCREAMING_SNAKE(key)>` (mechanical camelCase →
 * SCREAMING_SNAKE, prefixed with `AGENT_RUNNER_` to match the binary). E.g.
 * `AGENT_RUNNER_AGENT_CMD`, `AGENT_RUNNER_PI_BIN`, `AGENT_RUNNER_DEFAULT_ARBITER`,
 * `AGENT_RUNNER_PER_REPO_MAX`.
 *
 * Each value is coerced per the key's type and a typo/invalid value FAILS LOUDLY
 * (never silently ignored) with a message naming the offending variable.
 */

/** The shared `AGENT_RUNNER_` prefix on every env config variable. */
export const ENV_PREFIX = 'AGENT_RUNNER_';

/** How a key's env value is coerced from its raw string. */
type Coercion =
	| 'string'
	| 'boolean'
	| 'number'
	| 'list'
	| {enum: readonly string[]};

/**
 * The coercion to apply per {@link Config} key. The source of truth for which
 * env vars exist and how their raw strings become typed values. EVERY `Config`
 * key appears here (host-only included) — env is a per-machine source, so no key
 * is off-limits. Keys not listed have no env var.
 */
const KEY_COERCIONS: {[K in keyof Config]-?: Coercion} = {
	allowAgents: 'boolean',
	maxParallel: 'number',
	perRepoMax: 'number',
	defaultArbiter: 'string',
	workspacesDir: 'string',
	arbitersDir: 'string',
	humanWorktreesDir: 'string',
	integration: {enum: ['propose', 'merge']},
	provider: {enum: ['none', 'github']},
	agentCmd: 'string',
	model: 'string',
	harness: {enum: ['null', 'pi']},
	piBin: 'string',
	verify: 'list',
};

/** camelCase config key → SCREAMING_SNAKE (`perRepoMax` → `PER_REPO_MAX`). */
function screamingSnake(key: string): string {
	return key.replace(/([a-z0-9])([A-Z])/g, '$1_$2').toUpperCase();
}

/** The `AGENT_RUNNER_*` env var name for a config key. */
export function envVarName(key: keyof Config): string {
	return ENV_PREFIX + screamingSnake(key);
}

/** A raw env map (defaults to `process.env`). */
export type EnvMap = Record<string, string | undefined>;

/**
 * Coerce a raw env string for one key, FAILING LOUDLY (with the offending var
 * name) on invalid input: booleans accept only `true`/`false`; numbers reject
 * NaN; enums must be in their union; list keys split on comma; strings verbatim.
 */
function coerceValue(
	varName: string,
	raw: string,
	coercion: Coercion,
): unknown {
	if (typeof coercion === 'object') {
		// Enum: validate against the union.
		if (!coercion.enum.includes(raw)) {
			throw new Error(
				`Invalid value for ${varName}: '${raw}'. ` +
					`Expected one of: ${coercion.enum.join(', ')}.`,
			);
		}
		return raw;
	}
	switch (coercion) {
		case 'string':
			return raw;
		case 'boolean':
			if (raw === 'true') {
				return true;
			}
			if (raw === 'false') {
				return false;
			}
			throw new Error(
				`Invalid boolean for ${varName}: '${raw}'. Expected 'true' or 'false'.`,
			);
		case 'number': {
			const n = Number(raw);
			if (raw.trim() === '' || Number.isNaN(n)) {
				throw new Error(
					`Invalid number for ${varName}: '${raw}'. Expected a numeric value.`,
				);
			}
			return n;
		}
		case 'list':
			// Split on comma (cross-platform; not `:`), trimming each entry. An empty
			// string ⇒ an empty list (an explicit "clear" of a list key).
			return raw
				.split(',')
				.map((s) => s.trim())
				.filter((s) => s !== '');
	}
}

/**
 * Read the `AGENT_RUNNER_*` env layer into a {@link PartialConfig}. Only vars
 * actually present (and non-`undefined`) contribute, so absent env ⇒ `{}` and
 * built-in floors/defaults are untouched. Each present var is coerced per its
 * key's type; an invalid value throws LOUDLY naming the variable.
 *
 * Env may set ANY key — host-only included — because env is a per-machine
 * source, NOT the committed repo file (see this module's doc + ADR §13).
 */
export function envOverrides(env: EnvMap = process.env): PartialConfig {
	const overrides: PartialConfig = {};
	for (const key of Object.keys(KEY_COERCIONS) as (keyof Config)[]) {
		const varName = envVarName(key);
		const raw = env[varName];
		if (raw === undefined) {
			continue;
		}
		const value = coerceValue(varName, raw, KEY_COERCIONS[key]);
		// Type matches by construction: each coercion yields the key's value type.
		(overrides as Record<string, unknown>)[key] = value;
	}
	return overrides;
}

import {readFileSync, existsSync} from 'node:fs';
import {join} from 'node:path';
import {mergeConfig, type Config, type PartialConfig} from './config.js';
import {envOverrides, type EnvMap} from './env-config.js';

/**
 * The per-repo config layer.
 *
 * A repo may commit a `.agent-runner.json` at its root. It travels WITH the repo
 * (it is committed) and overrides the global `~/.config/agent-runner/config.json`
 * FOR THAT REPO ONLY — so repo-local properties (how this repo integrates, its
 * acceptance `verify` gate, which remote arbitrates its claims) are agreed by all
 * collaborators and agents rather than living in one person's global config.
 *
 * Resolution is per-key, highest wins:
 *
 *   flag (where a command offers one) > ENV (AGENT_RUNNER_*) > per-repo file >
 *   global > built-in default
 *
 * The mechanism is multi-repo aware: each repo resolves against its OWN
 * `.agent-runner.json`, so repo A can be `merge` while repo B is `propose` in the
 * SAME run (see {@link resolveRepoConfig}).
 *
 * Only keys that are genuinely repo properties are honoured in the COMMITTED
 * per-repo file. Runner/host-only keys (`piBin`, `agentCmd`, `maxParallel`, …)
 * describe the runner or the host machine, NOT a single repo;
 * if present in a per-repo file they are ignored and reported with a clear
 * message ({@link loadRepoConfig}).
 *
 * The sharpened host-only principle (ADR §13): **host-only keys must come from a
 * per-machine source — a CLI flag, an `AGENT_RUNNER_*` env var, or the global
 * config file — NEVER the committed repo file.** The allow/reject split below
 * therefore governs ONLY the committed repo file; env (a per-machine source like
 * the global file / a flag) may set ANY key, host-only included (see
 * {@link envOverrides}).
 *
 * A repo with no `.agent-runner.json` resolves to exactly the global config —
 * behaviour is unchanged from before this layer existed.
 */

/** The conventional per-repo config filename, committed at the repo root. */
export const REPO_CONFIG_FILENAME = '.agent-runner.json';

/**
 * Config keys that are genuinely repo properties and so are honoured in a
 * per-repo `.agent-runner.json`. Deliberately a subset of {@link Config};
 * extend this list as more keys become legitimately repo-scoped.
 */
export const REPO_ALLOWED_KEYS = [
	'integration',
	'provider',
	'verify',
	'defaultArbiter',
	'allowAgents',
	// `model` (which model this repo's work runs on) and `harness` (which adapter)
	// are legitimate repo properties (ADR §13) — model is routing intent, not auth,
	// and a repo may prefer a given harness. `piBin`/`agentCmd` stay host-only
	// (machine paths/commands), so they are rejected below.
	'model',
	'harness',
] as const satisfies readonly (keyof Config)[];

/** A key honoured in a per-repo file. */
export type RepoAllowedKey = (typeof REPO_ALLOWED_KEYS)[number];

/**
 * Config keys that describe the RUNNER or the HOST machine, not a single repo,
 * and so are rejected (ignored + reported) in a per-repo file. These remain the
 * domain of the global config / CLI flags.
 */
export const REPO_REJECTED_KEYS = [
	'maxParallel',
	'perRepoMax',
	'agentCmd',
	// `piBin` is a machine PATH/command, not repo policy, so it is host-only and
	// rejected per-repo (ADR §13). It must come from a per-machine source — a
	// flag, an `AGENT_RUNNER_PI_BIN` env var, or the global file — never a
	// committed repo file. (`harness`, by contrast, is repo-appropriate and so is
	// deliberately NOT rejected.)
	'piBin',
	// Reserved/future host-only keys callers may name; rejected proactively so a
	// typo or a copy-pasted global config never silently leaks host policy into a
	// repo. (`humanWorktreesDir` is a planned host-only path.)
	'humanWorktreesDir',
] as const;

/** A key rejected from a per-repo file. */
export type RepoRejectedKey = (typeof REPO_REJECTED_KEYS)[number];

const ALLOWED_SET = new Set<string>(REPO_ALLOWED_KEYS);

/** The path to a repo's `.agent-runner.json` (repo root + filename). */
export function repoConfigPath(repoPath: string): string {
	return join(repoPath, REPO_CONFIG_FILENAME);
}

/** The result of reading (and filtering) a repo's `.agent-runner.json`. */
export interface LoadedRepoConfig {
	/** Where we looked (whether or not the file exists). */
	path: string;
	/**
	 * Only the repo-appropriate keys found in the file, ready to layer over the
	 * global config. Unknown and rejected keys are NOT present here.
	 */
	config: PartialConfig;
	/**
	 * Runner/host-only keys that WERE present in the file and were ignored. Empty
	 * when nothing was rejected.
	 */
	rejected: string[];
	/**
	 * A clear, human-facing message naming the rejected keys and the file they
	 * came from. `undefined` when nothing was rejected.
	 */
	message?: string;
}

/**
 * Read a repo's `.agent-runner.json` and split it into the honoured subset and
 * the rejected runner/host-only keys. A missing file is not an error (the repo
 * simply resolves to the global config); invalid JSON is. Unknown keys are
 * silently dropped (neither honoured nor reported as rejected). Only keys in
 * {@link REPO_ALLOWED_KEYS} are carried into `config`.
 */
export function loadRepoConfig(repoPath: string): LoadedRepoConfig {
	const path = repoConfigPath(repoPath);
	if (!existsSync(path)) {
		return {path, config: {}, rejected: []};
	}

	let raw: string;
	try {
		raw = readFileSync(path, 'utf8');
	} catch (err) {
		throw new Error(`Failed to read ${path}: ${(err as Error).message}`);
	}

	let parsed: Record<string, unknown>;
	try {
		parsed = JSON.parse(raw) as Record<string, unknown>;
	} catch (err) {
		throw new Error(`Invalid JSON in ${path}: ${(err as Error).message}`);
	}

	const config: PartialConfig = {};
	const rejected: string[] = [];
	for (const key of Object.keys(parsed)) {
		const value = parsed[key];
		if (value === undefined) {
			continue;
		}
		if (ALLOWED_SET.has(key)) {
			// Type matches by construction: key ∈ REPO_ALLOWED_KEYS ⊂ keyof Config.
			(config as Record<string, unknown>)[key] = value;
		} else if (isRejectedKey(key)) {
			rejected.push(key);
		}
		// else: unknown key ⇒ silently ignored.
	}

	const message =
		rejected.length > 0
			? `Ignoring runner/host-only key(s) in ${REPO_CONFIG_FILENAME} ` +
				`(${path}): ${rejected.join(', ')}. ` +
				`These describe the runner/host, not a single repo, and belong in ` +
				`the global config or a CLI flag.`
			: undefined;

	return {path, config, rejected, ...(message ? {message} : {})};
}

function isRejectedKey(key: string): boolean {
	return (REPO_REJECTED_KEYS as readonly string[]).includes(key);
}

/** Inputs to {@link resolveRepoConfig}. */
export interface ResolveRepoConfigOptions {
	/** Absolute path to the repo root (where `.agent-runner.json` would live). */
	repoPath: string;
	/**
	 * The fully-resolved GLOBAL config (already merged over built-in defaults,
	 * e.g. via {@link mergeConfig} / `loadConfig`). The per-repo file and any
	 * flags layer OVER this; it provides the global + default layers of the
	 * precedence chain.
	 */
	global: Config;
	/**
	 * Command-level flag overrides (where a command offers one). These sit at the
	 * TOP of the precedence chain: flag > env > per-repo > global > default. Only
	 * keys a command actually exposes need appear here.
	 */
	flags?: PartialConfig;
	/**
	 * The raw environment map the `AGENT_RUNNER_*` layer is read from (defaults to
	 * `process.env`). Env sits ABOVE the per-repo file and BELOW a flag, and — as
	 * a per-machine source — may set ANY key, host-only included (it is NOT subject
	 * to the per-repo allow/reject split). Injectable so tests need not mutate the
	 * real `process.env`.
	 */
	env?: EnvMap;
}

/** The effective config for one repo, plus any rejected-key diagnostics. */
export interface ResolvedRepoConfig {
	/** The layered, effective {@link Config} for this repo. */
	config: Config;
	/** Runner/host-only keys ignored in this repo's file (see {@link loadRepoConfig}). */
	rejected: string[];
	/** Clear message for the rejected keys, if any. */
	message?: string;
}

/**
 * Resolve the effective config for ONE repo by layering, per key:
 *
 *   flag > ENV (AGENT_RUNNER_*) > per-repo `.agent-runner.json` > global >
 *   built-in default
 *
 * The `global` argument already carries the global + default layers (it is the
 * output of `loadConfig`/`mergeConfig`). We layer the repo's honoured keys over
 * it, then the `AGENT_RUNNER_*` env layer over that (env may set host-only keys
 * the per-repo file rejected — it is a per-machine source), then any flags on
 * top. The shared `global` object is never mutated, so calling this once per repo
 * in a multi-repo run yields INDEPENDENT results — repo A can be `merge` while
 * repo B is `propose` in the same run.
 *
 * A repo with no `.agent-runner.json` (and no env) resolves to exactly `global`
 * (unchanged behaviour).
 */
export function resolveRepoConfig(
	options: ResolveRepoConfigOptions,
): ResolvedRepoConfig {
	const {repoPath, global, flags, env} = options;
	const repo = loadRepoConfig(repoPath);
	// mergeConfig copies `global` (spreads DEFAULT_CONFIG then assigns) so the
	// shared global object is never mutated. Layer per-repo, then env (a
	// per-machine source — may set host-only keys), then flags on top.
	const config = mergeConfig({
		...global,
		...repo.config,
		...envOverrides(env),
		...(flags ?? {}),
	});
	return {
		config,
		rejected: repo.rejected,
		...(repo.message ? {message: repo.message} : {}),
	};
}

import type {Config, IntegrationMode, PartialConfig} from './config.js';

/**
 * The CLI flags that select WHICH agent runs and HOW it is launched — shared,
 * verbatim, by `run` and `do`. Both commands offer `--harness`/`--agent-cmd`/
 * `--pi-bin`/`--model`; this is the single place their string→`PartialConfig`
 * mapping lives so there is exactly ONE override path (not a parallel one per
 * command). `cli.ts`'s `runFlagOverrides` and {@link doFlagOverrides} both fold
 * this in.
 */
export interface HarnessFlags {
	agentCmd?: string;
	model?: string;
	harness?: string;
	piBin?: string;
}

/**
 * Map the shared harness/adapter flags into a {@link PartialConfig} of overrides
 * — the per-key mapping `run` and `do` both reuse. Only flags actually present
 * contribute (absent flag ⇒ absent key), so the override layer never clobbers a
 * lower precedence source with `undefined`. `--harness` is validated against the
 * `HarnessAdapter` union (an out-of-range value is dropped, matching `run`).
 */
export function harnessFlagOverrides(flags: HarnessFlags): PartialConfig {
	const overrides: PartialConfig = {};
	if (flags.agentCmd !== undefined) {
		overrides.agentCmd = flags.agentCmd;
	}
	if (flags.model !== undefined) {
		overrides.model = flags.model;
	}
	if (flags.harness === 'null' || flags.harness === 'pi') {
		overrides.harness = flags.harness;
	}
	if (flags.piBin !== undefined) {
		overrides.piBin = flags.piBin;
	}
	return overrides;
}

/**
 * Build the flag-override `PartialConfig` for the `do` command. This is the FIX
 * for the silent-drop bug: `do` DECLARES `--harness`/`--agent-cmd`/`--pi-bin`/
 * `--model`, so its action MUST thread them into `resolveRepoConfig`'s `flags`
 * — not just `{integration}`. It reuses the SAME per-key mapping `run` uses
 * ({@link harnessFlagOverrides}), then folds in the integrate-time mode (the
 * already-resolved `--merge`/`--propose`, via `integrationFromFlags`) so the
 * full set rides the same precedence chain (flag > env > per-repo > global >
 * default).
 */
export function doFlagOverrides(
	flags: HarnessFlags,
	integration?: IntegrationMode,
): PartialConfig {
	const overrides = harnessFlagOverrides(flags);
	if (integration !== undefined) {
		overrides.integration = integration;
	}
	return overrides;
}

/**
 * The null-default guard: the `null` adapter shells out to `agentCmd`, so it is
 * required there; the `pi` adapter invokes the pi CLI directly and does not
 * consume `agentCmd`. Returns `true` when the resolved config selects the null
 * adapter with no `agentCmd` — the case `do`/`run` must reject with a clear
 * "no agentCmd configured" error. (Same predicate both commands inline; named
 * here so the fix's no-regression test can pin it.)
 */
export function doNeedsAgentCmd(config: Config): boolean {
	return config.harness !== 'pi' && config.agentCmd.trim() === '';
}

import {performStart} from './start.js';
import {performComplete} from './complete.js';
import {resolveSlug, SlugResolutionError} from './slug-namespace.js';
import {resolveSlice, buildAgentPrompt, PromptError} from './prompt.js';
import {NullHarness, type Harness} from './harness.js';
import {PiHarness, piSessionDir} from './pi-harness.js';
import {SessionTailer} from './watch-session.js';
import {ledgerRead, type LedgerReadStrategy} from './ledger-read.js';
import type {IntegrationMode, ReviewProviderName} from './config.js';
import type {VerifyConfig} from './verify.js';
import {runAsync} from './git.js';

/**
 * `agent-runner do <slug>` (in-place form) — the per-repo, in-place WORKER that
 * claims + builds + gates + integrates in ONE checkout, then EXITS (ADR §3).
 * **This is the CI command** (CI has a checkout, is one repo, is one triggered
 * invocation, exits) and it ABSORBS the manual `ar-run.sh` test-driver.
 *
 * The in-place `do` is exactly `ar-run.sh`'s composition — `start` →
 * (autonomous prompt-fed harness run) → `complete` — guarded by a DIRTY-TREE
 * REFUSAL. It does NOT fork a third pipeline: it COMPOSES the existing human
 * verbs (which already do the dirty-guard-adjacent onboarding, branch switch,
 * gate, integrate, and branch tidy), with the autonomous agent invocation as the
 * ONLY new middle step. The runner owns EVERY git-state transition (claim,
 * done-move, completion commit, integration); the agent only edits code.
 *
 * The in-place ISOLATION (ADR §3): the current checkout / CI container IS the
 * isolation — no hub mirror, no external worktree. `performStart` puts the
 * checkout on `work/<slug>` cut from the freshly-fetched `<arbiter>/main` (the
 * isolation-strategy-seam's in-place strategy is the seam form of this same
 * "switch the checkout to work/<slug>" step; composing `start` reuses it
 * directly with the claim + dirty-aware onboarding already wired). `do --remote`
 * (the job-worktree strategy) is the SEPARATE `do-remote` slice; auto-pick /
 * multi-arg / `-n` is `do-autopick`.
 *
 * **CRITICAL — `do` is AUTONOMOUS, so its failure path is `run`'s, NOT
 * `complete`'s.** On a red gate / rebase conflict, `performComplete` routes the
 * item to needs-attention via the SAME seam call as `run`'s `runOneItem`, but
 * `complete` calls it WITHOUT an arbiter (the human path: a human is right
 * there). `do` runs UNATTENDED, so it MUST get the autonomous, arbiter-passed
 * surfacing like `run` (the on-`main` cherry-pick that makes a stuck CI run
 * visible to `scan`/`status`/another machine). We achieve this by passing
 * `surfaceArbiter` into `performComplete` (resolution (a) from the slice): the
 * success path reuses `complete`'s machinery; only the NEEDS-ATTENTION routing
 * becomes the autonomous variant.
 *
 * `--propose` (default) / `--merge` is resolved at integrate-time exactly like
 * `complete` (the caller threads the resolved mode in as `integration`).
 */

/** The terminal status of one in-place `do` run. */
export type DoOutcome =
	| 'completed' // claimed/onboarded → agent → gate green → integrated → exited
	| 'lost' // claim lost the race — skipped cleanly
	| 'contended' // claim push kept being rejected
	| 'needs-attention' // red gate / rebase conflict → surfaced (autonomous)
	| 'agent-failed' // the agent invocation itself errored before the gate
	| 'refused' // refused (dirty tree, wrong folder, nothing to complete, …)
	| 'usage-error' // usage / environment problem, or a slug-resolution error
	| 'prd-not-wired'; // `do prd:<slug>` — the slicing path is not built yet

export interface DoResult {
	exitCode: 0 | 1 | 2 | 3;
	outcome: DoOutcome;
	/** The resolved bare slug acted on (slice or PRD), when one was resolved. */
	slug?: string;
	/** The work branch the run operated on, when one was created/switched-to. */
	branch?: string;
	/** Human-readable summary of the terminal condition. */
	message: string;
}

/** The agent invocation: edits code in `cwd` to satisfy the prompt. */
export type DoAgentRunner = (input: {
	cwd: string;
	prompt: string;
	slug: string;
	env?: NodeJS.ProcessEnv;
}) => {ok: boolean; detail?: string};

export interface DoOptions {
	/** The raw CLI slug argument: bare (= slice), `slice:<slug>`, or `prd:<slug>`. */
	arg: string;
	/** The working clone/checkout to run in-place in. */
	cwd: string;
	/** Name of the arbiter git remote. Defaults to `origin`. */
	arbiter?: string;
	/** Integration mode resolved at integrate-time (flag > per-repo > global > default). */
	integration?: IntegrationMode;
	/** The declared per-repo acceptance gate (string | list). */
	verify?: VerifyConfig;
	/** Review-request provider override (propose mode); auto-detect when unset. */
	provider?: ReviewProviderName;
	/**
	 * The autonomous agent invocation. Tests inject this to edit files directly;
	 * production wires the harness seam (the prompt-fed, run-to-completion launch
	 * `run` uses). When omitted, {@link harness} is used.
	 */
	agentRunner?: DoAgentRunner;
	/** The harness seam used when `agentRunner` is omitted; defaults to the null adapter. */
	harness?: Harness;
	/**
	 * `do --watch`: stream the agent's high-signal events live by tailing the pi
	 * session `.jsonl` (slice `do-watch`, option (a)). A READ-ONLY observer — it
	 * NEVER changes the run's outcome, gate, integration, git, or exit code; only a
	 * concurrent log-tail is added. REQUIRES the pi harness (the null adapter has
	 * no session log to tail) — passing it with a non-pi harness is a usage error.
	 */
	watch?: boolean;
	/** The configured agent command the harness shells out to (null adapter). */
	agentCmd?: string;
	/** The model routing intent forwarded to the harness (ADR §13). */
	model?: string;
	/** Override the read seam (slug resolution); defaults to {@link ledgerRead}. */
	read?: LedgerReadStrategy;
	/** Override the resolver's repo path (slug-namespace existence reads). Defaults to `cwd`. */
	repoPath?: string;
	/** Environment for child git/agent processes. */
	env?: NodeJS.ProcessEnv;
	/** Sink for human-readable progress notes. */
	note?: (message: string) => void;
	/**
	 * Sink for a pre-formatted block printed VERBATIM (forwarded to `complete`'s
	 * propose-mode next-step block). Defaults to `note`.
	 */
	noteBlock?: (message: string) => void;
	/** Emit ANSI color in `complete`'s (cosmetic) propose next-step block. */
	color?: boolean;
	/**
	 * Where `--watch`'s tailed events are written (defaults to stderr). Tests inject
	 * a sink to assert the surfaced lines without a real terminal.
	 */
	watchSink?: (line: string) => void;
}

const DEFAULT_ARBITER = 'origin';

/**
 * Run the in-place `do` ritual end-to-end. Never throws for the expected
 * lost/contended/refused/needs-attention cases — those are returned with the
 * appropriate exit code and outcome. The runner owns all git; the agent only
 * edits code.
 */
export async function performDo(options: DoOptions): Promise<DoResult> {
	const note = options.note ?? (() => {});
	const arbiter = options.arbiter ?? DEFAULT_ARBITER;
	const cwd = options.cwd;
	const env = options.env;

	// 0. `--watch` REQUIRES the pi harness (slice `do-watch`): only the pi adapter
	//    writes a session `.jsonl` event log to tail. The null/shell adapter has no
	//    session log / event taxonomy, so there is nothing to observe — ERROR
	//    CLEARLY here, BEFORE any git transition (no claim, no branch), rather than
	//    silently running without the view. The injected `agentRunner` (tests /
	//    custom embeddings) is its own launch path and is exempt.
	if (
		options.watch === true &&
		options.agentRunner === undefined &&
		!(options.harness instanceof PiHarness)
	) {
		return {
			exitCode: 1,
			outcome: 'usage-error',
			message:
				'`do --watch` requires the pi harness; configure `harness: pi` or drop ' +
				'`--watch`.',
		};
	}

	// 1. Resolve the slug across BOTH namespaces — `do` is the ONE command that
	//    spans them (ADR §3a): bare → slice (after a no-PRD-collision check;
	//    ERROR on collision), `slice:`/`prd:` explicit. A collision / resolution
	//    failure is a loud usage error (exit 1).
	let resolved;
	try {
		resolved = resolveSlug({
			arg: options.arg,
			repoPath: options.repoPath ?? cwd,
			read: options.read ?? ledgerRead,
		});
	} catch (err) {
		if (err instanceof SlugResolutionError) {
			return {exitCode: 1, outcome: 'usage-error', message: err.message};
		}
		const message = err instanceof Error ? err.message : String(err);
		return {exitCode: 1, outcome: 'usage-error', message};
	}

	// 2. `do prd:<slug>` → the PRD-SLICING path. THIS slice only wires the
	//    resolver so `do` accepts + dispatches `prd:` correctly; the actual
	//    slicing orchestration is the reshaped `autoslice-command` slice (blocked
	//    on this one). Reach the slicing-path entry with a clear "not yet wired"
	//    stub — do NOT reimplement slicing here.
	if (resolved.namespace === 'prd') {
		const message =
			`'${resolved.slug}' is a PRD; \`do prd:${resolved.slug}\` would SLICE it, ` +
			'but the PRD-slicing path is not wired yet (it lands with the ' +
			'autoslice-command slice). Slice the PRD manually for now.';
		note(message);
		return {
			exitCode: 1,
			outcome: 'prd-not-wired',
			slug: resolved.slug,
			message,
		};
	}

	const slug = resolved.slug;

	// 3. Refuse on a DIRTY working tree (ar-run.sh's first guard). `do` runs in a
	//    REAL checkout (the human's clone / the CI container); it must NOT
	//    entangle unrelated work or run over uncommitted changes. (Mirrors the
	//    bash driver: "error: working tree is dirty — commit/stash before
	//    running a slice.")
	if (await isDirtyTree(cwd, env)) {
		const message =
			`working tree is dirty — commit or stash before running '${slug}' ` +
			'(do runs in-place in this checkout and will not entangle unrelated ' +
			'changes).';
		return {exitCode: 1, outcome: 'refused', slug, message};
	}

	// 4. Onboard like `start`: claim (only if needed) AND switch the checkout to
	//    work/<slug> off the freshly-fetched <arbiter>/main (the agent edits ON
	//    the work branch). A lost/contended claim is propagated verbatim and
	//    skipped cleanly — `do` never re-claims an in-progress item.
	const started = await performStart({slug, cwd, arbiter, env, note});
	if (started.outcome === 'lost') {
		return {exitCode: 2, outcome: 'lost', slug, message: started.message};
	}
	if (started.outcome === 'contended') {
		return {exitCode: 3, outcome: 'contended', slug, message: started.message};
	}
	if (started.exitCode !== 0) {
		// refused (in-progress without --resume, done/absent, not-ready) or a
		// usage/environment error: surface verbatim. `do` does not force-resume an
		// already-claimed item.
		const outcome: DoOutcome =
			started.outcome === 'refused' ? 'refused' : 'usage-error';
		return {exitCode: 1, outcome, slug, message: started.message};
	}
	const branch = started.branch;

	// 5. Run the agent autonomously in the checkout, ON the work branch — the
	//    SAME prompt assembly `agent-runner prompt` emits (canonical wrapper +
	//    source PRD + the slice's ## Prompt). The agent only edits code (it does
	//    no git). This is the one NEW middle step `ar-run.sh` shelled out for
	//    (`prompt | pi`).
	let prompt: string;
	try {
		const slice = resolveSlice(cwd, slug);
		prompt = buildAgentPrompt(slice.slug, slice.prd, slice.slicePrompt);
	} catch (err) {
		if (err instanceof PromptError) {
			return {
				exitCode: 1,
				outcome: 'agent-failed',
				slug,
				branch,
				message: err.message,
			};
		}
		throw err;
	}

	let agent: {ok: boolean; detail?: string};
	try {
		agent = await runDoAgent(options, cwd, prompt, slug);
	} catch (err) {
		const message = err instanceof Error ? err.message : String(err);
		return {exitCode: 1, outcome: 'agent-failed', slug, branch, message};
	}
	if (!agent.ok) {
		const message = agent.detail ?? `the agent failed to build '${slug}'.`;
		return {exitCode: 1, outcome: 'agent-failed', slug, branch, message};
	}

	// 6. Gate + done-move + commit + rebase + integrate + branch-tidy LIKE
	//    `complete` — but with the AUTONOMOUS needs-attention surfacing (pass
	//    `surfaceArbiter` so a red gate / rebase conflict surfaces on the
	//    arbiter's main, cross-machine visible — a stuck CI `do` that only routed
	//    locally would be invisible). The success path reuses `complete`'s
	//    machinery unchanged.
	const completed = await performComplete({
		slug,
		cwd,
		arbiter,
		integration: options.integration,
		verify: options.verify,
		provider: options.provider,
		// The autonomous failure-surfacing: route stuck items to the arbiter's
		// main (the `run` semantics), NOT local-only (the human `complete`).
		surfaceArbiter: arbiter,
		color: options.color,
		note,
		noteBlock: options.noteBlock,
		env,
	});

	if (completed.outcome === 'completed') {
		return {
			exitCode: 0,
			outcome: 'completed',
			slug,
			branch,
			message: completed.message,
		};
	}
	if (
		completed.outcome === 'gate-failed' ||
		completed.outcome === 'rebase-conflict'
	) {
		// Red gate / rebase conflict — routed to needs-attention (surfaced on the
		// arbiter). The work did NOT complete; the runner owns the bounce.
		return {
			exitCode: 1,
			outcome: 'needs-attention',
			slug,
			branch,
			message: completed.message,
		};
	}
	// refused (nothing to commit, wrong folder) / usage-error: surface verbatim.
	const outcome: DoOutcome =
		completed.outcome === 'refused' ? 'refused' : 'usage-error';
	return {exitCode: 1, outcome, slug, branch, message: completed.message};
}

/**
 * Run the agent against the checkout. Prefers the injected `agentRunner` (tests
 * / custom embeddings); otherwise launches `agentCmd` through the harness seam
 * (the null adapter by default), forwarding the model routing intent.
 *
 * With `--watch` (pi harness only, validated earlier), the agent is launched
 * NON-BLOCKING (`PiHarness.launchAsync` — `spawn`, not `spawnSync`) so a
 * {@link SessionTailer} can READ the growing session `.jsonl` concurrently and
 * surface the high-signal events live. The tailer is a pure observer: the
 * launch result returned here is IDENTICAL to the non-watch path, so outcome /
 * gate / git / exit code are unchanged — only a concurrent log-tail is added.
 */
async function runDoAgent(
	options: DoOptions,
	cwd: string,
	prompt: string,
	slug: string,
): Promise<{ok: boolean; detail?: string}> {
	if (options.agentRunner) {
		return options.agentRunner({cwd, prompt, slug, env: options.env});
	}
	const harness = options.harness ?? new NullHarness();

	// `--watch` (pi only): launch async + tail the session .jsonl concurrently.
	// (The non-pi case is already rejected as a usage error before any git
	// transition, so reaching here with watch ⇒ a PiHarness.)
	if (options.watch === true && harness instanceof PiHarness) {
		const tailer = new SessionTailer({
			sessionDir: piSessionDir(cwd),
			color: options.color ?? false,
			sink: options.watchSink,
		});
		tailer.start();
		try {
			const launched = await harness.launchAsync({
				dir: cwd,
				slug,
				command: options.agentCmd ?? '',
				prompt,
				model: options.model,
				env: options.env,
			});
			return {ok: launched.ok, detail: launched.detail};
		} finally {
			// Always release the tailer (one final drain) — even on a launch error —
			// so the observer never outlives the run or leaks a handle.
			await tailer.stop();
		}
	}

	const launched = harness.launch({
		dir: cwd,
		slug,
		command: options.agentCmd ?? '',
		prompt,
		model: options.model,
		env: options.env,
	});
	return {ok: launched.ok, detail: launched.detail};
}

/**
 * True when the working tree has uncommitted (unstaged OR staged) changes — the
 * dirty-tree refusal predicate (ar-run.sh: `git diff --quiet` AND
 * `git diff --cached --quiet`). Read-only.
 */
async function isDirtyTree(
	cwd: string,
	env: NodeJS.ProcessEnv | undefined,
): Promise<boolean> {
	const unstaged = await runAsync('git', ['diff', '--quiet'], cwd, {env});
	if (unstaged.status !== 0) {
		return true;
	}
	const staged = await runAsync('git', ['diff', '--cached', '--quiet'], cwd, {
		env,
	});
	return staged.status !== 0;
}

